"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { triggerShake, getRandomComplete } from "@/lib/learningMessages";
import { getNextStep } from "@/content";

// ===== 网格规格：4 列 × 3 行 =====
const COLS = 4;
const ROWS = 3;
const TOTAL = COLS * ROWS; // 12

type MicroStep = "3a" | "3b" | "3c";
type ViewMode = "row" | "column";

const STEP_LABELS: Record<MicroStep, string> = {
  "3a": "摆一摆",
  "3b": "理一理",
  "3c": "数一数",
};

export default function CountPage() {
  // ===== 全局状态 =====
  const [microStep, setMicroStep] = useState<MicroStep>("3a");
  const [completeMsg, setCompleteMsg] = useState("");

  // ===== 3a：摆一摆 =====
  const [cells, setCells] = useState<boolean[]>(
    Array.from({ length: TOTAL }, () => false)
  );
  const [dragging, setDragging] = useState(false);
  const [dragPos, setDragPos] = useState({ x: 0, y: 0 });
  const [hoveredCell, setHoveredCell] = useState<number | null>(null);
  const [totalAnswer, setTotalAnswer] = useState("");
  const [totalSolved, setTotalSolved] = useState(false);
  const totalInputRef = useRef<HTMLInputElement>(null);

  const filledCount = cells.filter(Boolean).length;
  const allFilled = filledCount === TOTAL;

  // --- 拖拽逻辑（pointer events） ---
  const onDragStart = (e: React.PointerEvent) => {
    if (allFilled) return;
    e.currentTarget.setPointerCapture(e.pointerId);
    setDragging(true);
    setDragPos({ x: e.clientX, y: e.clientY });
  };

  const onDragMove = (e: React.PointerEvent) => {
    if (!dragging) return;
    setDragPos({ x: e.clientX, y: e.clientY });
    const el = document.elementFromPoint(e.clientX, e.clientY);
    const cellEl = el?.closest<HTMLElement>("[data-cell-index]");
    if (cellEl) {
      const idx = Number(cellEl.dataset.cellIndex);
      setHoveredCell(!cells[idx] ? idx : null);
    } else {
      setHoveredCell(null);
    }
  };

  const onDragEnd = (e: React.PointerEvent) => {
    if (!dragging) return;
    const el = document.elementFromPoint(e.clientX, e.clientY);
    const cellEl = el?.closest<HTMLElement>("[data-cell-index]");
    if (cellEl) {
      const idx = Number(cellEl.dataset.cellIndex);
      if (!cells[idx]) {
        const next = [...cells];
        next[idx] = true;
        setCells(next);
      }
    }
    setDragging(false);
    setHoveredCell(null);
  };

  const onDragCancel = () => {
    setDragging(false);
    setHoveredCell(null);
  };

  // --- 总数提交 ---
  const onTotalSubmit = () => {
    if (!totalAnswer) return;
    if (Number(totalAnswer) === TOTAL) {
      setTotalSolved(true);
      setCompleteMsg(getRandomComplete());
    } else {
      triggerShake(totalInputRef.current);
      setTotalAnswer("");
    }
  };

  // ===== 3b：理一理 =====
  const [viewMode, setViewMode] = useState<ViewMode | null>(null);
  const [perGroup, setPerGroup] = useState("");
  const [perGroupSolved, setPerGroupSolved] = useState(false);
  const [groupCount, setGroupCount] = useState("");
  const [bPhase, setBPhase] = useState<"input" | "check" | "done">("input");
  const perGroupRef = useRef<HTMLInputElement>(null);
  const groupCountRef = useRef<HTMLInputElement>(null);
  const sameRef = useRef<HTMLDivElement>(null);

  const effectiveViewMode: ViewMode = viewMode ?? "row";
  const expectedPerGroup = effectiveViewMode === "row" ? COLS : ROWS;
  const expectedGroupCount = effectiveViewMode === "row" ? ROWS : COLS;
  const groupLabel = effectiveViewMode === "row" ? "行" : "列";

  // 行/列高亮循环（animate-pulse-highlight）
  const [highlightIdx, setHighlightIdx] = useState(0);
  useEffect(() => {
    if (microStep !== "3b" || !viewMode) return;
    const max = viewMode === "row" ? ROWS : COLS;
    const id = setInterval(() => {
      setHighlightIdx((p) => (p + 1) % max);
    }, 1500);
    return () => clearInterval(id);
  }, [microStep, viewMode]);

  const onPerGroupSubmit = () => {
    if (!perGroup) return;
    if (Number(perGroup) === expectedPerGroup) {
      setPerGroupSolved(true);
      setTimeout(() => groupCountRef.current?.focus(), 100);
    } else {
      triggerShake(perGroupRef.current);
      setPerGroup("");
    }
  };

  const onGroupCountSubmit = () => {
    if (!groupCount) return;
    if (Number(groupCount) === expectedGroupCount) {
      setBPhase("check");
    } else {
      triggerShake(groupCountRef.current);
      setGroupCount("");
    }
  };

  const onSameAnswer = (ans: "yes" | "no") => {
    if (ans === "yes") {
      setBPhase("done");
    } else {
      triggerShake(sameRef.current);
    }
  };

  // ===== 3c：数一数 =====
  const [cPhase, setCPhase] = useState(0);
  // cPhase: 0=初始, 1..numGroups=逐组高亮+连加, numGroups+1=乘法展示, numGroups+2=完成
  const groupSize = effectiveViewMode === "column" ? ROWS : COLS;
  const numGroups = effectiveViewMode === "column" ? COLS : ROWS;

  useEffect(() => {
    if (microStep !== "3c") return;
    if (cPhase >= numGroups + 2) return;
    const delay = cPhase === 0 ? 800 : cPhase <= numGroups ? 1200 : 1500;
    const id = setTimeout(() => setCPhase((p) => p + 1), delay);
    return () => clearTimeout(id);
  }, [microStep, cPhase, numGroups]);

  const cHighlightIdx =
    cPhase >= 1 && cPhase <= numGroups ? cPhase - 1 : -1;
  const showAddition = cPhase >= 1 && cPhase <= numGroups;
  const showMultiplication = cPhase >= numGroups + 1 && cPhase < numGroups + 2;
  const showComplete = cPhase >= numGroups + 2;

  const additionTerms: number[] = [];
  for (let i = 0; i < Math.min(cPhase, numGroups); i++) {
    additionTerms.push(groupSize);
  }

  const replay3c = () => setCPhase(0);
  const nextStep = getNextStep("area", "count");

  // ===== 微步骤进度指示器 =====
  const currentStepIdx = (["3a", "3b", "3c"] as MicroStep[]).indexOf(
    microStep
  );

  // ===== 渲染网格（三步共用） =====
  const renderGrid = () => (
    <div
      className="mx-auto grid w-full max-w-[360px] select-none gap-2"
      style={{ gridTemplateColumns: `repeat(${COLS}, 1fr)` }}
    >
      {Array.from({ length: TOTAL }, (_, idx) => {
        const row = Math.floor(idx / COLS);
        const col = idx % COLS;
        const filled = cells[idx];

        // 高亮判定
        let highlighted = false;
        if (microStep === "3b" && viewMode) {
          highlighted =
            viewMode === "row" ? row === highlightIdx : col === highlightIdx;
        } else if (microStep === "3c" && cHighlightIdx >= 0) {
          highlighted =
            effectiveViewMode === "row"
              ? row === cHighlightIdx
              : col === cHighlightIdx;
        }

        const isHovered = microStep === "3a" && hoveredCell === idx;

        let cellClass: string;
        if (highlighted) {
          cellClass = "animate-pulse-highlight";
        } else if (filled) {
          cellClass = "bg-[var(--signal-confirmed)]";
        } else if (isHovered) {
          cellClass =
            "border-2 border-[var(--signal-focus)] bg-[var(--signal-focus)]/30";
        } else {
          cellClass = "border-2 border-dashed border-[var(--signal-pending)]";
        }

        return (
          <div
            key={idx}
            data-cell-index={idx}
            className={`aspect-square rounded-lg transition-all duration-200 ${cellClass}`}
          />
        );
      })}
    </div>
  );

  return (
    <StepShell topicId="area" stepId="count">
      {/* 微步骤进度条 */}
      <div className="mb-6 flex items-center justify-center gap-2">
        {(["3a", "3b", "3c"] as MicroStep[]).map((s, i) => (
          <div key={s} className="flex items-center gap-2">
            <div
              className={`rounded-full px-3 py-1 text-sm transition-colors ${
                i === currentStepIdx
                  ? "bg-[var(--signal-focus)] font-semibold text-[var(--text)]"
                  : i < currentStepIdx
                  ? "bg-[var(--signal-confirmed)]/20 text-[var(--signal-confirmed)]"
                  : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
              }`}
            >
              {i < currentStepIdx ? "✓ " : ""}
              {STEP_LABELS[s]}
            </div>
            {i < 2 && <div className="h-px w-4 bg-[var(--border)]" />}
          </div>
        ))}
      </div>

      {/* ===== 3a：摆一摆 ===== */}
      {microStep === "3a" && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <h2 className="text-lg font-semibold text-[var(--text)]">
              摆一摆
            </h2>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              把下面的蓝色方块拖到网格里，一个一个摆上去
            </p>
          </div>

          {renderGrid()}

          {/* 当前计数 */}
          <div className="text-center text-lg text-[var(--text)]">
            已经放了{" "}
            <span className="font-bold text-[var(--primary)]">
              {filledCount}
            </span>{" "}
            块
          </div>

          {/* 源方块（拖拽起点） */}
          {!allFilled && (
            <div className="flex flex-col items-center gap-2">
              <div
                onPointerDown={onDragStart}
                onPointerMove={onDragMove}
                onPointerUp={onDragEnd}
                onPointerCancel={onDragCancel}
                className="h-16 w-16 cursor-grab touch-none rounded-lg bg-[var(--signal-confirmed)] shadow-[var(--shadow-md)] animate-bounce-soft active:cursor-grabbing"
              />
              <span className="text-xs text-[var(--text-muted)]">
                拖我上去
              </span>
            </div>
          )}

          {/* 拖拽中的浮动方块 */}
          {dragging && (
            <div
              className="pointer-events-none fixed z-50 h-16 w-16 rounded-lg bg-[var(--signal-confirmed)] opacity-80"
              style={{ left: dragPos.x - 32, top: dragPos.y - 32 }}
            />
          )}

          {/* 填满后：总数问答 */}
          {allFilled && !totalSolved && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <p className="text-xl font-semibold text-[var(--text)]">
                一共多少块？
              </p>
              <div className="mt-4 flex justify-center gap-3">
                <input
                  ref={totalInputRef}
                  type="text"
                  inputMode="numeric"
                  value={totalAnswer}
                  onChange={(e) =>
                    setTotalAnswer(e.target.value.replace(/[^0-9]/g, ""))
                  }
                  onKeyDown={(e) => e.key === "Enter" && onTotalSubmit()}
                  className="w-24 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-2xl font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                  placeholder="?"
                  autoFocus
                />
                <button
                  onClick={onTotalSubmit}
                  className="rounded-lg bg-[var(--primary)] px-6 py-2 font-medium text-white transition-colors hover:bg-[var(--primary-dark)]"
                >
                  确定
                </button>
              </div>
            </div>
          )}

          {/* 3a 完成 */}
          {totalSolved && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="text-4xl">🎉</div>
              <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                一共 {TOTAL} 块！
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                {completeMsg}
              </p>
              <button
                onClick={() => setMicroStep("3b")}
                className="mt-4 rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white transition-colors hover:bg-[var(--accent-dark)]"
              >
                继续探索 →
              </button>
            </div>
          )}
        </div>
      )}

      {/* ===== 3b：理一理 ===== */}
      {microStep === "3b" && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <h2 className="text-lg font-semibold text-[var(--text)]">
              理一理
            </h2>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              {viewMode
                ? `按${groupLabel}看——黄色闪烁的就是一${groupLabel}`
                : "有没有更快的办法？选一种方式看看"}
            </p>
          </div>

          {renderGrid()}

          {/* 选择查看方式 */}
          {!viewMode && (
            <div className="flex justify-center gap-4">
              <button
                onClick={() => {
                  setViewMode("row");
                  setHighlightIdx(0);
                }}
                className="rounded-xl bg-[var(--signal-focus)] px-8 py-4 text-lg font-semibold text-[var(--text)] shadow-[var(--shadow-sm)] transition-transform hover:-translate-y-1"
              >
                按行看
              </button>
              <button
                onClick={() => {
                  setViewMode("column");
                  setHighlightIdx(0);
                }}
                className="rounded-xl bg-[var(--signal-focus)] px-8 py-4 text-lg font-semibold text-[var(--text)] shadow-[var(--shadow-sm)] transition-transform hover:-translate-y-1"
              >
                按列看
              </button>
            </div>
          )}

          {/* 输入每行/列数量 + 行/列数 */}
          {viewMode && bPhase === "input" && (
            <div className="space-y-4 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <div className="flex flex-wrap items-center justify-center gap-3">
                <span className="text-[var(--text)]">
                  每{groupLabel}有几个？
                </span>
                <input
                  ref={perGroupRef}
                  type="text"
                  inputMode="numeric"
                  value={perGroup}
                  disabled={perGroupSolved}
                  onChange={(e) =>
                    setPerGroup(e.target.value.replace(/[^0-9]/g, ""))
                  }
                  onKeyDown={(e) => e.key === "Enter" && onPerGroupSubmit()}
                  className={`w-20 rounded-lg border-2 px-3 py-2 text-center text-lg font-bold focus:outline-none ${
                    perGroupSolved
                      ? "border-[var(--signal-success)] text-[var(--signal-success)]"
                      : "border-[var(--border)] text-[var(--text)] focus:border-[var(--primary)]"
                  }`}
                  placeholder="?"
                  autoFocus
                />
                {!perGroupSolved ? (
                  <button
                    onClick={onPerGroupSubmit}
                    className="rounded-lg bg-[var(--primary)] px-4 py-2 font-medium text-white"
                  >
                    确定
                  </button>
                ) : (
                  <span className="text-lg text-[var(--signal-success)]">
                    ✓
                  </span>
                )}
              </div>

              {perGroupSolved && (
                <div className="flex animate-float-in flex-wrap items-center justify-center gap-3">
                  <span className="text-[var(--text)]">
                    一共有几{groupLabel}？
                  </span>
                  <input
                    ref={groupCountRef}
                    type="text"
                    inputMode="numeric"
                    value={groupCount}
                    onChange={(e) =>
                      setGroupCount(e.target.value.replace(/[^0-9]/g, ""))
                    }
                    onKeyDown={(e) =>
                      e.key === "Enter" && onGroupCountSubmit()
                    }
                    className="w-20 rounded-lg border-2 border-[var(--border)] px-3 py-2 text-center text-lg font-bold text-[var(--text)] focus:border-[var(--primary)] focus:outline-none"
                    placeholder="?"
                    autoFocus
                  />
                  <button
                    onClick={onGroupCountSubmit}
                    className="rounded-lg bg-[var(--primary)] px-4 py-2 font-medium text-white"
                  >
                    确定
                  </button>
                </div>
              )}
            </div>
          )}

          {/* 自检节点 */}
          {bPhase === "check" && (
            <div
              ref={sameRef}
              className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]"
            >
              <p className="text-lg text-[var(--text)]">
                每{groupLabel}一样多吗？
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                如果不一样多，还能这样算吗？
              </p>
              <div className="mt-4 flex justify-center gap-4">
                <button
                  onClick={() => onSameAnswer("yes")}
                  className="rounded-xl bg-[var(--signal-confirmed)] px-10 py-3 text-lg font-medium text-white"
                >
                  是
                </button>
                <button
                  onClick={() => onSameAnswer("no")}
                  className="rounded-xl border-2 border-[var(--signal-pending)] bg-[var(--bg-soft)] px-10 py-3 text-lg font-medium text-[var(--text-secondary)]"
                >
                  否
                </button>
              </div>
            </div>
          )}

          {/* 3b 完成 */}
          {bPhase === "done" && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="text-4xl">✨</div>
              <p className="mt-2 text-lg text-[var(--text)]">
                没错！每{groupLabel} {expectedPerGroup} 个，有{" "}
                {expectedGroupCount} {groupLabel}，都一样多。
              </p>
              <button
                onClick={() => {
                  setMicroStep("3c");
                  setCPhase(0);
                  setCompleteMsg(getRandomComplete());
                }}
                className="mt-4 rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white transition-colors hover:bg-[var(--accent-dark)]"
              >
                一起算 →
              </button>
            </div>
          )}
        </div>
      )}

      {/* ===== 3c：数一数 ===== */}
      {microStep === "3c" && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <h2 className="text-lg font-semibold text-[var(--text)]">
              数一数
            </h2>
            <p className="mt-1 text-sm text-[var(--text-secondary)]">
              {showComplete
                ? "原来乘法就是这么数的！"
                : `看看按${groupLabel}数有多快`}
            </p>
          </div>

          {renderGrid()}

          {/* 连加 → 乘法 动画区 */}
          <div className="flex min-h-[100px] items-center justify-center">
            {cPhase === 0 && (
              <p className="animate-float-in text-lg text-[var(--text-secondary)]">
                准备好了吗？
              </p>
            )}

            {showAddition && (
              <div className="animate-float-in text-3xl font-bold text-[var(--text)]">
                {additionTerms.map((t, i) => (
                  <span key={i}>
                    {i > 0 && (
                      <span className="mx-2 text-[var(--text-secondary)]">
                        +
                      </span>
                    )}
                    {t}
                  </span>
                ))}
              </div>
            )}

            {showMultiplication && (
              <div className="animate-float-in text-center">
                <div className="text-2xl font-bold text-[var(--text)]">
                  {additionTerms.map((t, i) => (
                    <span key={i}>
                      {i > 0 && (
                        <span className="mx-1.5 text-[var(--text-secondary)]">
                          +
                        </span>
                      )}
                      {t}
                    </span>
                  ))}{" "}
                  = {groupSize * numGroups}
                </div>
                <div className="mt-3 text-4xl font-bold text-[var(--primary)]">
                  {groupSize} × {numGroups} = {groupSize * numGroups}
                </div>
              </div>
            )}
          </div>

          {/* 完成 */}
          {showComplete && (
            <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-sm)]">
              <div className="text-4xl">🎉</div>
              <p className="mt-2 text-lg font-semibold text-[var(--text)]">
                {numGroups} 个 {groupSize} 加起来是 {groupSize * numGroups}
              </p>
              <p className="mt-1 text-2xl font-bold text-[var(--primary)]">
                {groupSize} × {numGroups} = {groupSize * numGroups}
              </p>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                {completeMsg || "太棒了！你发现了乘法的秘密！"}
              </p>
              <div className="mt-4 flex justify-center gap-3">
                <button
                  onClick={replay3c}
                  className="rounded-full bg-[var(--bg-soft)] px-6 py-3 font-medium text-[var(--text-secondary)]"
                >
                  再看一遍
                </button>
                {nextStep && (
                  <Link
                    href={nextStep.path}
                    className="rounded-full bg-[var(--accent)] px-8 py-3 font-medium text-white transition-colors hover:bg-[var(--accent-dark)]"
                  >
                    进入下一步 →
                  </Link>
                )}
              </div>
            </div>
          )}
        </div>
      )}
    </StepShell>
  );
}
